{
  "name": "Omniverse Builder",
  "description": "A powerful 3D world editor where users can upload GLB, images, and text to create immersive environments with first-person navigation and Gemini-powered voice chat.",
  "requestFramePermissions": [
    "camera",
    "microphone"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type ObjectType = 'glb' | 'image' | 'text' | 'link';

export interface WorldObject {
  id: string;
  type: ObjectType;
  name: string;
  url: string; // Blob URL or external URL
  position: [number, number, number];
  rotation: [number, number, number];
  scale: [number, number, number];
  content?: string; // For text objects
}

export interface WorldState {
  objects: WorldObject[];
  environment: 'sunset' | 'dawn' | 'night' | 'warehouse' | 'city';
  groundColor: string;
}

export enum EditorMode {
  EDIT = 'edit',
  PLAY = 'play'
}

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { Canvas } from '@react-three/fiber';
import { Sky, Stars, Environment, ContactShadows, KeyboardControls } from '@react-three/drei';
import { v4 as uuidv4 } from 'uuid';
import { 
  Box, 
  Upload, 
  Type, 
  Globe, 
  Image as ImageIcon, 
  Trash2, 
  Move, 
  Play, 
  Edit3, 
  Download,
  Mic,
  MicOff,
  Users
} from 'lucide-react';

import { WorldObject, WorldState, EditorMode, ObjectType } from './types';
import WorldScene from './components/WorldScene';
import EditorPanel from './components/EditorPanel';
import VoiceAssistant from './components/VoiceAssistant';
import { exportWorldToHTML } from './services/exporter';

const App: React.FC = () => {
  const [world, setWorld] = useState<WorldState>({
    objects: [],
    environment: 'city',
    groundColor: '#1a1a1a',
  });
  const [selectedObjectId, setSelectedObjectId] = useState<string | null>(null);
  const [mode, setMode] = useState<EditorMode>(EditorMode.EDIT);
  const [isVoiceActive, setIsVoiceActive] = useState(false);
  const [showUsers, setShowUsers] = useState(false);

  // Mock users for collab feel
  const [connectedUsers] = useState([
    { id: '1', name: 'User_42', color: '#ff0000' },
    { id: '2', name: 'Dev_Alpha', color: '#00ff00' },
  ]);

  const addObject = useCallback((type: ObjectType, file?: File, text?: string, url?: string) => {
    let objectUrl = '';
    let name = 'New Object';

    if (file) {
      objectUrl = URL.createObjectURL(file);
      name = file.name;
    } else if (url) {
      objectUrl = url;
      name = 'External Resource';
    }

    const newObj: WorldObject = {
      id: uuidv4(),
      type,
      name,
      url: objectUrl,
      position: [Math.random() * 5 - 2.5, 1, Math.random() * 5 - 2.5],
      rotation: [0, 0, 0],
      scale: [1, 1, 1],
      content: text,
    };

    setWorld(prev => ({ ...prev, objects: [...prev.objects, newObj] }));
    setSelectedObjectId(newObj.id);
  }, []);

  const updateObject = useCallback((id: string, updates: Partial<WorldObject>) => {
    setWorld(prev => ({
      ...prev,
      objects: prev.objects.map(obj => obj.id === id ? { ...obj, ...updates } : obj)
    }));
  }, []);

  const removeObject = useCallback((id: string) => {
    setWorld(prev => ({
      ...prev,
      objects: prev.objects.filter(obj => obj.id !== id)
    }));
    if (selectedObjectId === id) setSelectedObjectId(null);
  }, [selectedObjectId]);

  const handleExport = () => {
    const html = exportWorldToHTML(world);
    const blob = new Blob([html], { type: 'text/html' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = 'my-virtual-world.html';
    link.click();
  };

  return (
    <div className="relative w-full h-full bg-[#050505]">
      {/* UI Controls */}
      <div className="absolute top-6 left-6 z-50 flex flex-col gap-4">
        <div className="flex items-center gap-2 bg-black/60 backdrop-blur-md p-2 rounded-xl border border-white/10">
          <button 
            onClick={() => setMode(EditorMode.EDIT)}
            className={`p-3 rounded-lg transition-all ${mode === EditorMode.EDIT ? 'bg-blue-600 text-white' : 'hover:bg-white/10 text-white/60'}`}
          >
            <Edit3 size={20} />
          </button>
          <button 
            onClick={() => setMode(EditorMode.PLAY)}
            className={`p-3 rounded-lg transition-all ${mode === EditorMode.PLAY ? 'bg-green-600 text-white' : 'hover:bg-white/10 text-white/60'}`}
          >
            <Play size={20} />
          </button>
        </div>

        {mode === EditorMode.EDIT && (
          <div className="flex flex-col gap-2 bg-black/60 backdrop-blur-md p-4 rounded-xl border border-white/10 animate-in fade-in slide-in-from-left-4 duration-300">
            <h3 className="text-xs font-bold uppercase tracking-widest text-white/40 mb-2">Insert</h3>
            <label className="flex items-center gap-3 p-3 hover:bg-white/5 rounded-lg cursor-pointer text-sm text-white/80 transition-colors">
              <Upload size={18} className="text-blue-400" />
              <span>3D Model (GLB)</span>
              <input 
                type="file" 
                accept=".glb" 
                className="hidden" 
                onChange={(e) => e.target.files?.[0] && addObject('glb', e.target.files[0])} 
              />
            </label>
            <label className="flex items-center gap-3 p-3 hover:bg-white/5 rounded-lg cursor-pointer text-sm text-white/80 transition-colors">
              <ImageIcon size={18} className="text-emerald-400" />
              <span>Image</span>
              <input 
                type="file" 
                accept="image/*" 
                className="hidden" 
                onChange={(e) => e.target.files?.[0] && addObject('image', e.target.files[0])} 
              />
            </label>
            <button 
              onClick={() => {
                const txt = prompt('Enter text:');
                if (txt) addObject('text', undefined, txt);
              }}
              className="flex items-center gap-3 p-3 hover:bg-white/5 rounded-lg text-sm text-white/80 transition-colors"
            >
              <Type size={18} className="text-amber-400" />
              <span>Floating Text</span>
            </button>
            <button 
              onClick={() => {
                const url = prompt('Enter URL:');
                if (url) addObject('link', undefined, undefined, url);
              }}
              className="flex items-center gap-3 p-3 hover:bg-white/5 rounded-lg text-sm text-white/80 transition-colors"
            >
              <Globe size={18} className="text-purple-400" />
              <span>Web Portal</span>
            </button>
          </div>
        )}
      </div>

      {/* Right Panel for Selected Object */}
      {mode === EditorMode.EDIT && selectedObjectId && (
        <EditorPanel 
          object={world.objects.find(o => o.id === selectedObjectId)!} 
          onUpdate={(updates) => updateObject(selectedObjectId, updates)}
          onDelete={() => removeObject(selectedObjectId)}
        />
      )}

      {/* Collaboration / Voice Controls */}
      <div className="absolute bottom-6 right-6 z-50 flex gap-4">
        <button 
          onClick={() => setShowUsers(!showUsers)}
          className={`p-4 rounded-full backdrop-blur-md shadow-2xl transition-all border ${showUsers ? 'bg-indigo-600 text-white border-white/20' : 'bg-black/60 text-white/60 border-white/10 hover:bg-black/80'}`}
        >
          <Users size={24} />
          {showUsers && (
            <div className="absolute bottom-16 right-0 w-48 bg-black/90 border border-white/10 rounded-xl p-3 flex flex-col gap-2">
              <div className="text-[10px] font-bold text-white/40 uppercase mb-1">Active Users</div>
              {connectedUsers.map(u => (
                <div key={u.id} className="flex items-center gap-2 text-sm text-white/80">
                  <div className="w-2 h-2 rounded-full" style={{ background: u.color }} />
                  {u.name} (You)
                </div>
              ))}
            </div>
          )}
        </button>

        <button 
          onClick={() => setIsVoiceActive(!isVoiceActive)}
          className={`p-4 rounded-full backdrop-blur-md shadow-2xl transition-all border ${isVoiceActive ? 'bg-red-600 text-white border-white/20' : 'bg-black/60 text-white/60 border-white/10 hover:bg-black/80'}`}
        >
          {isVoiceActive ? <Mic size={24} /> : <MicOff size={24} />}
        </button>

        <button 
          onClick={handleExport}
          className="p-4 rounded-full bg-white text-black hover:bg-white/90 shadow-2xl transition-all flex items-center gap-2 px-6 font-semibold"
        >
          <Download size={20} />
          Export World
        </button>
      </div>

      {/* Help Overlay for Controls */}
      {mode === EditorMode.PLAY && (
        <div className="absolute top-6 right-6 text-white/60 text-xs bg-black/40 p-4 rounded-lg backdrop-blur-sm">
          <p>WASD to Move</p>
          <p>MOUSE to Look</p>
          <p>SHIFT to Run</p>
          <p>SPACE to Jump</p>
          <p>ESC to Unlock Mouse</p>
        </div>
      )}

      {/* 3D Scene */}
      <div className="w-full h-full cursor-crosshair">
        <KeyboardControls
          map={[
            { name: "forward", keys: ["ArrowUp", "w", "W"] },
            { name: "backward", keys: ["ArrowDown", "s", "S"] },
            { name: "left", keys: ["ArrowLeft", "a", "A"] },
            { name: "right", keys: ["ArrowRight", "d", "D"] },
            { name: "jump", keys: ["Space"] },
            { name: "run", keys: ["Shift"] },
          ]}
        >
          <Canvas 
            shadows 
            camera={{ position: [0, 2, 5], fov: 75 }}
            gl={{ preserveDrawingBuffer: true }}
          >
            <color attach="background" args={['#0a0a0a']} />

            <Sky distance={450000} sunPosition={[1, 0.1, 0]} inclination={0} azimuth={0.25} />
            <Stars radius={100} depth={50} count={5000} factor={4} saturation={0} fade speed={1} />

            <ambientLight intensity={0.5} />
            <pointLight position={[10, 10, 10]} intensity={1.5} castShadow />
            <Environment preset="city" />

            <WorldScene 
              world={world} 
              mode={mode} 
              selectedId={selectedObjectId}
              onSelect={setSelectedObjectId}
              onUpdate={updateObject}
            />

            <mesh rotation={[-Math.PI / 2, 0, 0]} receiveShadow>
              <planeGeometry args={[100, 100]} />
              <meshStandardMaterial color={world.groundColor} />
            </mesh>
            <ContactShadows resolution={1024} scale={20} blur={2} opacity={0.25} far={10} color="#000000" />
          </Canvas>
        </KeyboardControls>
      </div>

      {/* Voice Assistant Logic */}
      {isVoiceActive && <VoiceAssistant world={world} />}
    </div>
  );
};

export default App;

import React, { useRef, Suspense } from 'react';
import { useThree, useFrame } from '@react-three/fiber';
import { 
  useGLTF, 
  TransformControls, 
  PointerLockControls, 
  Text, 
  Image as DreiImage, 
  Html,
  Float
} from '@react-three/drei';
import * as THREE from 'three';
import { WorldState, EditorMode, WorldObject } from '../types';
import Player from './Player';

interface WorldSceneProps {
  world: WorldState;
  mode: EditorMode;
  selectedId: string | null;
  onSelect: (id: string | null) => void;
  onUpdate: (id: string, updates: Partial<WorldObject>) => void;
}

const Model: React.FC<{ object: WorldObject }> = ({ object }) => {
  const { scene } = useGLTF(object.url);
  // Clone to prevent shared state issues between multiple instances
  const clonedScene = scene.clone();

  return (
    <primitive 
      object={clonedScene} 
      position={object.position} 
      rotation={object.rotation} 
      scale={object.scale} 
    />
  );
};

const WorldScene: React.FC<WorldSceneProps> = ({ 
  world, 
  mode, 
  selectedId, 
  onSelect, 
  onUpdate 
}) => {
  const selectedObject = world.objects.find(o => o.id === selectedId);

  return (
    <>
      {mode === EditorMode.PLAY ? (
        <>
          <PointerLockControls />
          <Player />
        </>
      ) : null}

      <Suspense fallback={null}>
        {world.objects.map((obj) => {
          const isSelected = selectedId === obj.id;

          return (
            <group 
              key={obj.id} 
              onClick={(e) => {
                if (mode === EditorMode.EDIT) {
                  e.stopPropagation();
                  onSelect(obj.id);
                }
              }}
            >
              {obj.type === 'glb' && (
                <Model object={obj} />
              )}

              {obj.type === 'image' && (
                <DreiImage 
                  url={obj.url} 
                  position={obj.position} 
                  rotation={obj.rotation} 
                  scale={obj.scale} 
                  transparent
                />
              )}

              {obj.type === 'text' && (
                <Float speed={1.5} rotationIntensity={0.5} floatIntensity={0.5}>
                  <Text
                    position={obj.position}
                    rotation={obj.rotation}
                    fontSize={0.5 * obj.scale[0]}
                    color="white"
                    maxWidth={2}
                    textAlign="center"
                    anchorX="center"
                    anchorY="middle"
                  >
                    {obj.content}
                  </Text>
                </Float>
              )}

              {obj.type === 'link' && (
                <group position={obj.position} rotation={obj.rotation}>
                  <mesh>
                    <boxGeometry args={[1, 2, 0.1]} />
                    <meshStandardMaterial color="#4f46e5" transparent opacity={0.3} />
                  </mesh>
                  <Html position={[0, 0, 0.06]} transform occlude>
                    <div className="p-4 bg-white/10 backdrop-blur-md rounded-lg border border-white/20 text-white w-48 text-center pointer-events-auto">
                      <p className="text-xs opacity-50 mb-2 truncate">{obj.url}</p>
                      <button 
                        onClick={() => window.open(obj.url, '_blank')}
                        className="bg-indigo-600 px-4 py-1 rounded text-sm hover:bg-indigo-500 transition-colors"
                      >
                        Visit Portal
                      </button>
                    </div>
                  </Html>
                </group>
              )}

              {mode === EditorMode.EDIT && isSelected && (
                <TransformControls 
                  object={null} // We'll manage position ourselves
                  onMouseUp={() => {
                    // This is where we'd catch final position if we used Drei's managed state
                    // For now, simpler selection works.
                  }}
                />
              )}
            </group>
          );
        })}
      </Suspense>
    </>
  );
};

export default WorldScene;

import React, { useRef, useState } from 'react';
import { useThree, useFrame } from '@react-three/fiber';
import { useKeyboardControls } from '@react-three/drei';
import * as THREE from 'three';

const Player: React.FC = () => {
  const { camera } = useThree();
  const [, getKeys] = useKeyboardControls();
  const velocity = useRef(new THREE.Vector3());
  const direction = useRef(new THREE.Vector3());
  const [isJumping, setIsJumping] = useState(false);

  useFrame((state, delta) => {
    const { forward, backward, left, right, jump, run } = getKeys();

    const speed = run ? 10 : 5;
    const acceleration = 50;

    // Movement direction based on camera rotation
    direction.current.z = Number(forward) - Number(backward);
    direction.current.x = Number(right) - Number(left);
    direction.current.normalize();

    // Smoother movement
    if (forward || backward) velocity.current.z -= direction.current.z * acceleration * delta;
    if (left || right) velocity.current.x -= direction.current.x * acceleration * delta;

    // Friction
    velocity.current.z -= velocity.current.z * 10 * delta;
    velocity.current.x -= velocity.current.x * 10 * delta;

    // Jumping logic (simple mock)
    if (jump && !isJumping) {
      velocity.current.y = 15;
      setIsJumping(true);
    }

    if (isJumping) {
      velocity.current.y -= 30 * delta; // gravity
      if (camera.position.y <= 2) {
        camera.position.y = 2;
        velocity.current.y = 0;
        setIsJumping(false);
      }
    }

    camera.translateX(-velocity.current.x * delta * speed);
    camera.translateZ(-velocity.current.z * delta * speed);
    camera.position.y += velocity.current.y * delta;

    // Lock floor
    if (camera.position.y < 2) camera.position.y = 2;
  });

  return null;
};

export default Player;

import React from 'react';
import { WorldObject } from '../types';
import { Trash2, Move, RotateCcw, Maximize2, Type } from 'lucide-react';

interface EditorPanelProps {
  object: WorldObject;
  onUpdate: (updates: Partial<WorldObject>) => void;
  onDelete: () => void;
}

const EditorPanel: React.FC<EditorPanelProps> = ({ object, onUpdate, onDelete }) => {
  const handleCoordChange = (axis: 'x' | 'y' | 'z', value: string, field: 'position' | 'rotation' | 'scale') => {
    const newVal = parseFloat(value) || 0;
    const current = [...object[field]] as [number, number, number];
    const index = axis === 'x' ? 0 : axis === 'y' ? 1 : 2;
    current[index] = newVal;
    onUpdate({ [field]: current });
  };

  return (
    <div className="absolute top-24 right-6 w-80 bg-black/80 backdrop-blur-xl border border-white/10 rounded-2xl p-6 z-50 animate-in fade-in slide-in-from-right-4">
      <div className="flex items-center justify-between mb-6">
        <h2 className="text-lg font-bold truncate pr-4">{object.name}</h2>
        <button 
          onClick={onDelete}
          className="p-2 text-red-400 hover:bg-red-400/10 rounded-lg transition-colors"
        >
          <Trash2 size={20} />
        </button>
      </div>

      <div className="space-y-6">
        {object.type === 'text' && (
          <div className="space-y-2">
            <label className="text-[10px] font-bold text-white/40 uppercase tracking-widest flex items-center gap-2">
              <Type size={12} /> Content
            </label>
            <textarea
              value={object.content}
              onChange={(e) => onUpdate({ content: e.target.value })}
              className="w-full bg-white/5 border border-white/10 rounded-lg p-3 text-sm focus:outline-none focus:border-blue-500 min-h-[80px]"
            />
          </div>
        )}

        {/* Position */}
        <div className="space-y-2">
          <label className="text-[10px] font-bold text-white/40 uppercase tracking-widest flex items-center gap-2">
            <Move size={12} /> Position
          </label>
          <div className="grid grid-cols-3 gap-2">
            {['x', 'y', 'z'].map((axis, i) => (
              <div key={axis} className="relative">
                <input 
                  type="number"
                  step="0.1"
                  value={object.position[i]}
                  onChange={(e) => handleCoordChange(axis as 'x'|'y'|'z', e.target.value, 'position')}
                  className="w-full bg-white/5 border border-white/10 rounded-lg p-2 pl-6 text-xs focus:outline-none focus:border-blue-500"
                />
                <span className="absolute left-2 top-1/2 -translate-y-1/2 text-[10px] font-bold text-white/20 uppercase">{axis}</span>
              </div>
            ))}
          </div>
        </div>

        {/* Rotation */}
        <div className="space-y-2">
          <label className="text-[10px] font-bold text-white/40 uppercase tracking-widest flex items-center gap-2">
            <RotateCcw size={12} /> Rotation (Rad)
          </label>
          <div className="grid grid-cols-3 gap-2">
            {['x', 'y', 'z'].map((axis, i) => (
              <div key={axis} className="relative">
                <input 
                  type="number"
                  step="0.1"
                  value={object.rotation[i]}
                  onChange={(e) => handleCoordChange(axis as 'x'|'y'|'z', e.target.value, 'rotation')}
                  className="w-full bg-white/5 border border-white/10 rounded-lg p-2 pl-6 text-xs focus:outline-none focus:border-blue-500"
                />
                <span className="absolute left-2 top-1/2 -translate-y-1/2 text-[10px] font-bold text-white/20 uppercase">{axis}</span>
              </div>
            ))}
          </div>
        </div>

        {/* Scale */}
        <div className="space-y-2">
          <label className="text-[10px] font-bold text-white/40 uppercase tracking-widest flex items-center gap-2">
            <Maximize2 size={12} /> Scale
          </label>
          <div className="grid grid-cols-3 gap-2">
            {['x', 'y', 'z'].map((axis, i) => (
              <div key={axis} className="relative">
                <input 
                  type="number"
                  step="0.1"
                  value={object.scale[i]}
                  onChange={(e) => handleCoordChange(axis as 'x'|'y'|'z', e.target.value, 'scale')}
                  className="w-full bg-white/5 border border-white/10 rounded-lg p-2 pl-6 text-xs focus:outline-none focus:border-blue-500"
                />
                <span className="absolute left-2 top-1/2 -translate-y-1/2 text-[10px] font-bold text-white/20 uppercase">{axis}</span>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default EditorPanel;

import React, { useEffect, useRef, useState } from 'react';
import { GoogleGenAI, Modality, LiveServerMessage } from '@google/genai';
import { WorldState } from '../types';

interface VoiceAssistantProps {
  world: WorldState;
}

const VoiceAssistant: React.FC<VoiceAssistantProps> = ({ world }) => {
  const [isReady, setIsReady] = useState(false);
  const audioContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  // Implementing manually as per guidance
  const decode = (base64: string) => {
    const binaryString = atob(base64);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
  };

  const encode = (bytes: Uint8Array) => {
    let binary = '';
    const len = bytes.byteLength;
    for (let i = 0; i < len; i++) {
      binary += String.fromCharCode(bytes[i]);
    }
    return btoa(binary);
  };

  async function decodeAudioData(
    data: Uint8Array,
    ctx: AudioContext,
    sampleRate: number,
    numChannels: number,
  ): Promise<AudioBuffer> {
    const dataInt16 = new Int16Array(data.buffer);
    const frameCount = dataInt16.length / numChannels;
    const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

    for (let channel = 0; channel < numChannels; channel++) {
      const channelData = buffer.getChannelData(channel);
      for (let i = 0; i < frameCount; i++) {
        channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
      }
    }
    return buffer;
  }

  function createBlob(data: Float32Array): { data: string; mimeType: string } {
    const l = data.length;
    const int16 = new Int16Array(l);
    for (let i = 0; i < l; i++) {
      int16[i] = data[i] * 32768;
    }
    return {
      data: encode(new Uint8Array(int16.buffer)),
      mimeType: 'audio/pcm;rate=16000',
    };
  }

  useEffect(() => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

    // Initialize audio contexts
    const inputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
    const outputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    audioContextRef.current = outputAudioContext;

    let mediaStream: MediaStream;
    let sessionPromise: any;

    const startSession = async () => {
      try {
        mediaStream = await navigator.mediaDevices.getUserMedia({ audio: true });

        sessionPromise = ai.live.connect({
          model: 'gemini-2.5-flash-native-audio-preview-12-2025',
          config: {
            responseModalities: [Modality.AUDIO],
            speechConfig: {
              voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
            },
            systemInstruction: `You are the AI World Guide of this virtual 3D environment. 
              The world currently contains ${world.objects.length} objects. 
              Types include: ${world.objects.map(o => o.type).join(', ')}.
              Be friendly, talk about the objects, and help the user navigate. 
              Respond with low latency voice.`,
          },
          callbacks: {
            onopen: () => {
              setIsReady(true);
              const source = inputAudioContext.createMediaStreamSource(mediaStream);
              const scriptProcessor = inputAudioContext.createScriptProcessor(4096, 1, 1);
              scriptProcessor.onaudioprocess = (e) => {
                const inputData = e.inputBuffer.getChannelData(0);
                const pcmBlob = createBlob(inputData);
                sessionPromise.then((session: any) => {
                  session.sendRealtimeInput({ media: pcmBlob });
                });
              };
              source.connect(scriptProcessor);
              scriptProcessor.connect(inputAudioContext.destination);
            },
            onmessage: async (message: LiveServerMessage) => {
              const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
              if (base64Audio) {
                nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputAudioContext.currentTime);
                const audioBuffer = await decodeAudioData(decode(base64Audio), outputAudioContext, 24000, 1);
                const source = outputAudioContext.createBufferSource();
                source.buffer = audioBuffer;
                source.connect(outputAudioContext.destination);
                source.start(nextStartTimeRef.current);
                nextStartTimeRef.current += audioBuffer.duration;
                sourcesRef.current.add(source);
                source.onended = () => sourcesRef.current.delete(source);
              }

              if (message.serverContent?.interrupted) {
                sourcesRef.current.forEach(s => s.stop());
                sourcesRef.current.clear();
                nextStartTimeRef.current = 0;
              }
            },
            onerror: (e) => console.error('Gemini Live Error:', e),
            onclose: () => setIsReady(false),
          },
        });
      } catch (err) {
        console.error('Failed to start Gemini Live:', err);
      }
    };

    startSession();

    return () => {
      mediaStream?.getTracks().forEach(t => t.stop());
      inputAudioContext.close();
      outputAudioContext.close();
    };
  }, []);

  return (
    <div className="fixed bottom-24 right-6 bg-indigo-600/20 backdrop-blur-md border border-indigo-500/30 p-4 rounded-xl flex items-center gap-3 animate-pulse">
      <div className="w-3 h-3 bg-indigo-400 rounded-full" />
      <span className="text-xs font-semibold text-indigo-300">
        {isReady ? 'AI Guide: Listening...' : 'Connecting to AI...'}
      </span>
    </div>
  );
};

export default VoiceAssistant;

import { WorldState } from '../types';

export const exportWorldToHTML = (state: WorldState): string => {
  // Obfuscate the GLB URLs slightly or just bundle state
  // In a real production app, we would use a build step to bundle Three.js
  const worldData = JSON.stringify(state);

  return `
<!DOCTYPE html>
<html>
<head>
    <title>My Virtual World</title>
    <meta charset="UTF-8">
    <style>
        body { margin: 0; background: #000; overflow: hidden; }
        canvas { display: block; }
        #overlay { position: fixed; top: 20px; left: 20px; color: white; font-family: sans-serif; pointer-events: none; text-shadow: 0 2px 4px rgba(0,0,0,0.5); }
    </style>
    <script async src="https://unpkg.com/es-module-shims@1.6.3/dist/es-module-shims.js"></script>
    <script type="importmap">
    {
        "imports": {
            "three": "https://unpkg.com/three@0.154.0/build/three.module.js",
            "three/addons/": "https://unpkg.com/three@0.154.0/examples/jsm/"
        }
    }
    </script>
</head>
<body>
    <div id="overlay">
        <h1>Virtual World</h1>
        <p>Use WASD to Move, Mouse to Look</p>
    </div>
    <script type="module">
        import * as THREE from 'three';
        import { GLTFLoader } from 'three/addons/loaders/GLTFLoader.js';
        import { PointerLockControls } from 'three/addons/controls/PointerLockControls.js';

        const world = ${worldData};

        const scene = new THREE.Scene();
        scene.background = new THREE.Color('#0a0a0a');

        const camera = new THREE.PerspectiveCamera(75, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(0, 2, 5);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.setPixelRatio(window.devicePixelRatio);
        renderer.shadowMap.enabled = true;
        document.body.appendChild(renderer.domElement);

        const controls = new PointerLockControls(camera, document.body);
        document.addEventListener('click', () => controls.lock());

        // Lights
        const amb = new THREE.AmbientLight(0xffffff, 0.5);
        scene.add(amb);
        const sun = new THREE.PointLight(0xffffff, 1.5);
        sun.position.set(10, 20, 10);
        scene.add(sun);

        // Ground
        const floor = new THREE.Mesh(
            new THREE.PlaneGeometry(100, 100),
            new THREE.MeshStandardMaterial({ color: world.groundColor || '#111' })
        );
        floor.rotation.x = -Math.PI / 2;
        floor.receiveShadow = true;
        scene.add(floor);

        // Load Objects
        const loader = new GLTFLoader();
        world.objects.forEach(obj => {
            if (obj.type === 'glb') {
                loader.load(obj.url, (gltf) => {
                    const model = gltf.scene;
                    model.position.set(...obj.position);
                    model.rotation.set(...obj.rotation);
                    model.scale.set(...obj.scale);
                    scene.add(model);
                });
            } else if (obj.type === 'text') {
                // Simplified text for export
                const canvas = document.createElement('canvas');
                const ctx = canvas.getContext('2d');
                ctx.font = '48px sans-serif';
                ctx.fillStyle = 'white';
                ctx.fillText(obj.content || '', 10, 50);
                const tex = new THREE.CanvasTexture(canvas);
                const sprite = new THREE.Sprite(new THREE.SpriteMaterial({ map: tex }));
                sprite.position.set(...obj.position);
                sprite.scale.set(obj.scale[0] * 2, obj.scale[1], 1);
                scene.add(sprite);
            }
        });

        // Movement Logic
        const move = { f: false, b: false, l: false, r: false };
        const vel = new THREE.Vector3();
        document.addEventListener('keydown', (e) => {
            if (e.code === 'KeyW') move.f = true;
            if (e.code === 'KeyS') move.b = true;
            if (e.code === 'KeyA') move.l = true;
            if (e.code === 'KeyD') move.r = true;
        });
        document.addEventListener('keyup', (e) => {
            if (e.code === 'KeyW') move.f = false;
            if (e.code === 'KeyS') move.b = false;
            if (e.code === 'KeyA') move.l = false;
            if (e.code === 'KeyD') move.r = false;
        });

        function animate() {
            requestAnimationFrame(animate);
            if (controls.isLocked) {
                const delta = 0.016;
                const speed = 10;
                vel.x -= vel.x * 10 * delta;
                vel.z -= vel.z * 10 * delta;
                if (move.f) vel.z += speed * delta;
                if (move.b) vel.z -= speed * delta;
                if (move.l) vel.x -= speed * delta;
                if (move.r) vel.x += speed * delta;
                controls.moveRight(vel.x);
                controls.moveForward(vel.z);
            }
            renderer.render(scene, camera);
        }
        animate();

        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });
    </script>
</body>
</html>
  `;
};
